<?php declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/comercio.php';$id=filter_input(INPUT_GET,'id',FILTER_VALIDATE_INT,['options'=>['min_range'=>1]])?:0;$producto=productoPublico($id);if(!$producto){http_response_code(404);$pageTitle='Producto no encontrado | Atenea';}else $pageTitle=$producto['nombre'].' | Atenea';$pageDescription=$producto['descripcion_corta']??'Producto Atenea';$pageClass='course-details-page';$activePage='productos';require dirname(__DIR__,2).'/includes/header.php';if(!$producto):?><main class="main"><section class="section"><div class="container text-center"><h1>Producto no encontrado</h1><a class="btn-atenea" href="<?=atenea_url('src/website/pricing.php')?>">Volver a productos</a></div></section></main><?php require dirname(__DIR__,2).'/includes/footer.php';exit;endif;$pdo=obtenerConexion();$q=$pdo->prepare('SELECT ruta FROM producto_imagenes WHERE producto_id=:id ORDER BY orden,id');$q->execute(['id'=>$id]);$galeria=$q->fetchAll();$pc=$producto['precio_calculado'];$disponible=(int)$producto['stock']-(int)$producto['stock_reservado'];?>
<main class="main"><div class="page-title"><div class="heading"><div class="container text-center"><h1><?=atenea_e($producto['nombre'])?></h1><p><?=atenea_e($producto['descripcion_corta'])?></p></div></div><nav class="breadcrumbs"><div class="container"><ol><li><a href="<?=atenea_url('index.php')?>">Inicio</a></li><li><a href="<?=atenea_url('src/website/pricing.php')?>">Productos</a></li><li class="current">Detalle</li></ol></div></nav></div><section class="course-details section"><div class="container"><div class="row gy-4"><div class="col-lg-7"><img src="<?=imagenProducto($producto['imagen_principal'])?>" class="img-fluid rounded w-100" style="max-height:520px;object-fit:cover" alt="<?=atenea_e($producto['nombre'])?>"><?php if($galeria):?><div class="row g-2 mt-2"><?php foreach($galeria as$img):?><div class="col-4"><img src="<?=imagenProducto($img['ruta'])?>" class="img-fluid rounded" style="aspect-ratio:1;object-fit:cover" alt="Galería de <?=atenea_e($producto['nombre'])?>"></div><?php endforeach;?></div><?php endif;?><h2 class="mt-4">Descripción</h2><p><?=nl2br(atenea_e($producto['descripcion']))?></p></div><aside class="col-lg-5"><div class="pricing-item"><?php if($producto['categoria']):?><p class="text-muted"><?=atenea_e($producto['categoria'])?></p><?php endif;?><?php if($pc['promocion_valida']):?><span class="badge bg-danger mb-2"><?=atenea_e((string)($pc['promocion']['etiqueta']?:'Oferta'))?></span><p><del>$<?=number_format($pc['normal'],2)?></del></p><?php endif;?><h2>$<?=number_format($pc['final'],2)?> USD</h2><p><?=$disponible>0&&$producto['disponible']?'Disponible':'Agotado'?><?php if($disponible>0&&$disponible<=10):?> · <?=$disponible?> unidades<?php endif;?></p><?php if($disponible>0&&$producto['disponible']):?><form method="post" action="<?=atenea_url('src/pagos/crear-checkout.php')?>"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="producto_id" value="<?=$id?>"><label class="form-label">Cantidad</label><input class="form-control mb-3" type="number" name="cantidad" min="1" max="<?=$disponible?>" value="1" required><button class="buy-btn border-0" type="submit">Comprar</button></form><?php else:?><button class="buy-btn border-0 opacity-50" disabled>Agotado</button><?php endif;?></div></aside></div></div></section></main><?php require dirname(__DIR__,2).'/includes/footer.php';?>
